import java.util.*;
import java.lang.*;
import java.io.*;

class Trie
{
    static final int ALPHABET_SIZE = 26;

    static class TrieNode {
        TrieNode[] children;
        boolean isEndOfWord;

        TrieNode() {
            children = new TrieNode[ALPHABET_SIZE];
            isEndOfWord = false;
        }
    }

    TrieNode root;

    Trie() {
        root = new TrieNode();
    }

    void insert(String word) {
        TrieNode current = root;
        for (char ch : word.toCharArray()) {
            int index = ch - 'a';
            if (current.children[index] == null) {
                current.children[index] = new TrieNode();
            }
            current = current.children[index];
        }
        current.isEndOfWord = true;
    }



    boolean nodeHasNoChildren(TrieNode node) {
        return Arrays.stream(node.children).allMatch(child -> child == null) && !node.isEndOfWord;
    }

    boolean search(String word) {
        TrieNode node = searchNode(word);
        return (node != null && node.isEndOfWord);
    }

    TrieNode searchNode(String word) {
        TrieNode current = root;
        for (char ch : word.toCharArray()) {
            int index = ch - 'a';
            if (current.children[index] == null) {
                return null; // Character not found in the trie
            }
            current = current.children[index];
        }
        return current;
    }

    void printAllWords() {
        StringBuilder currentWord = new StringBuilder();
        printWordsRecursive(root, currentWord);
    }

    void printWordsRecursive(TrieNode node, StringBuilder currentWord) {
        if (node == null) {
            return;
        }

        if (node.isEndOfWord) {
            System.out.println(currentWord);
        }

        for (int i = 0; i < ALPHABET_SIZE; ++i) {
            if (node.children[i] != null) {
                currentWord.append((char) ('a' + i));
                printWordsRecursive(node.children[i], currentWord);
                currentWord.deleteCharAt(currentWord.length() - 1);
            }
        }
    }

    void autocomplete(String s) {
        TrieNode current = root;
        for (char ch : s.toCharArray()) {
            int index = ch - 'a';
            if (current.children[index] == null) {
                return;
            }
            current = current.children[index];
        }
        StringBuilder currentWord = new StringBuilder();
        currentWord.append(s);
        printWordsRecursive(current, currentWord);
    }
}
